function initOtp(container, options = {}) {
    const inputs = Array.from(container.querySelectorAll('input'));
    const hidden = options.hiddenInput || null;
    const length = 6;

    const isDigit = (v) => /^[0-9]$/.test(v);

    const getFirstEmptyIndex = () => {
        const idx = inputs.findIndex(i => i.value === '');
        return idx === -1 ? length - 1 : idx;
    };

    const isAllowedIndex = (idx) => {
        for (let i = 0; i < idx; i++) {
            if (inputs[i].value === '') return false;
        }
        return true;
    };

    const focusIndex = (idx) => {
        const i = Math.max(0, Math.min(length - 1, idx));
        inputs[i].focus();
        inputs[i].select();
    };

    const clampFocusToAllowed = () => {
        focusIndex(getFirstEmptyIndex());
    };

    const updateHidden = () => {
        const code = inputs.map(i => i.value).join('');
        if (hidden) hidden.value = code;

        inputs.forEach(i =>
            i.classList.toggle('filled', i.value !== '')
        );

        if (code.length === length && !code.includes('')) {
            container.dispatchEvent(
                new CustomEvent('otp:complete', { detail: { code } })
            );
        }
    };

    inputs.forEach((input, idx) => {
        input.addEventListener('mousedown', (e) => {
            if (!isAllowedIndex(idx)) {
                e.preventDefault();
                clampFocusToAllowed();
            }
        });

        input.addEventListener('focus', () => {
            if (!isAllowedIndex(idx)) {
                clampFocusToAllowed();
                return;
            }
            input.select();
        });

        input.addEventListener('beforeinput', (e) => {
            if (!isAllowedIndex(idx) && e.inputType !== 'deleteContentBackward') {
                e.preventDefault();
                clampFocusToAllowed();
            }
        });

        input.addEventListener('input', () => {
            if (!isAllowedIndex(idx)) {
                input.value = '';
                updateHidden();
                clampFocusToAllowed();
                return;
            }

            let v = input.value;
            if (v.length > 1) v = v.slice(-1);
            if (!isDigit(v)) v = '';

            input.value = v;
            updateHidden();

            if (v && idx < length - 1) {
                focusIndex(idx + 1);
            }
        });

        input.addEventListener('keydown', (e) => {
            if (!isAllowedIndex(idx) && e.key !== 'Backspace') {
                e.preventDefault();
                clampFocusToAllowed();
                return;
            }

            if (e.key === 'Backspace') {
                if (input.value === '' && idx > 0) {
                    e.preventDefault();
                    inputs[idx - 1].value = '';
                    updateHidden();
                    focusIndex(idx - 1);
                } else {
                    setTimeout(updateHidden, 0);
                }
                return;
            }

            if (e.key === 'ArrowLeft') {
                e.preventDefault();
                focusIndex(idx - 1);
                return;
            }

            if (e.key === 'ArrowRight') {
                e.preventDefault();
                const next = idx + 1;
                if (next < length && isAllowedIndex(next)) {
                    focusIndex(next);
                } else {
                    clampFocusToAllowed();
                }
                return;
            }

            if (e.key.length === 1 && !/^\d$/.test(e.key)) {
                e.preventDefault();
            }
        });
    });

    container.addEventListener('paste', (e) => {
        e.preventDefault();
        const text = (e.clipboardData || window.clipboardData).getData('text');
        const digits = (text.match(/\d/g) || []).slice(0, length);

        inputs.forEach(i => i.value = '');
        digits.forEach((d, i) => inputs[i].value = d);

        updateHidden();
        clampFocusToAllowed();
    });

    updateHidden();

    return {
        focus: () => clampFocusToAllowed(),
        clear: () => {
            inputs.forEach(i => i.value = '');
            updateHidden();
            clampFocusToAllowed();
        },
        getValue: () => inputs.map(i => i.value).join(''),
        setValue: (code) => {
            const digits = String(code || '').match(/\d/g) || [];
            inputs.forEach(i => i.value = '');
            digits.slice(0, length).forEach((d, i) => {
                inputs[i].value = d;
            });
            updateHidden();
            clampFocusToAllowed();
        }
    };
}

const otpEl = document.getElementById('otp');
const otpHidden = document.getElementById('otpValue');

if(otpEl){
    const otp = initOtp(otpEl, {
        hiddenInput: otpHidden
    });

    otp.focus();

    otpEl.addEventListener('otp:complete', (e) => {
        console.log('Код введён:', e.detail.code);
    });
}



